// Function to calculate the orientation of three points (p, q, r)
int orientation(Point const& p, Point const& q, Point const& r) {
	return (q.y - p.y) * (r.x - q.x) - (q.x - p.x) * (r.y - q.y);
}

// Function to calculate the convex hull using Graham's scan algorithm
std::vector<Point> convexHull(std::vector<Point> const& points) {
	int n = points.size();
	if (n < 3) return points; // If there are less than 3 points, they already form a convex hull

	// Find the point with the lowest y-coordinate and break ties by x-coordinate
	Point minPoint;
	minPoint.x = std::numeric_limits<double>::max();
	minPoint.y = std::numeric_limits<double>::max();
	for (int i = 0; i < n; ++i) {
		if (points[i].y < minPoint.y || (points[i].y == minPoint.y && points[i].x < minPoint.x)) {
			minPoint = points[i];
		}
	}

	// Sort the points based on the polar angle they make with the minimum point
	std::vector<Point> sortedPoints;
	for (int i = 0; i < n; ++i) {
		if (points[i] != minPoint) {
			sortedPoints.push_back(points[i]);
		}
	}

	// Sort the points based on the polar angle they make with the minimum point
	std::sort(sortedPoints.begin(), sortedPoints.end(), [&](const Point& a, const Point& b) {
		double crossProduct = (a.x - minPoint.x) * (b.y - minPoint.y) - (a.y - minPoint.y) * (b.x - minPoint.x);
		return crossProduct > 0 || (crossProduct == 0 && distance(minPoint, a) < distance(minPoint, b));
	});

	std::vector<Point> convexHullPoints;
	convexHullPoints.push_back(sortedPoints[0]);
	convexHullPoints.push_back(sortedPoints[1]);

	for (int i = 2; i < sortedPoints.size(); ++i) {
		while (orientation(convexHullPoints.back(), convexHullPoints[convexHullPoints.size() - 2], sortedPoints[i]) <= 0) {
			convexHullPoints.pop_back();
		}
		convexHullPoints.push_back(sortedPoints[i]);
	}

	return convexHullPoints;
}

// Function to calculate the perimeter of the smallest convex polygon that contains all the points
double convexHullPerimeter(std::vector<Point> const& points) {
	std::vector<Point> hull = convexHull(points);
	int n = hull.size();
	double perimeter = 0.0;

	#pragma omp parallel for reduction(+:perimeter)
	for (int i = 0; i < n; ++i) {
		Point p1 = hull[i];
		Point p2 = hull[(i + 1) % n]; // Wrap around to the first point after the last one
		perimeter += distance(p1, p2);
	}

	return perimeter;
}
